var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"크윽!?","JPN":"くっ！？","ENG":"Kgh?!","TWN":"呃？！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"몸상태가 별론가? 어째 저번보다 상대하기 까다롭지 않아?","JPN":"体調が悪いのかな？　なんだかこの前より相手しづらくない？","ENG":"Something feels off... Is it just me, or are they harder to deal with this time?","TWN":"身體狀況不太好嗎？怎麼感覺比上次更難對付了？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"침식파 반응은 이전과 비슷합니다. 하지만 이쪽의 기술을 꿰차고 있는 것처럼 움직이고 있어요!","JPN":"侵食波の反応は前と同じです。でも、こっちの技術を全部知っているように動いてるんです！","ENG":"The Corruption ray readings are similar to before. But they're moving like they know our next move!","TWN":"侵蝕波反應與之前相似。但是，它似乎掌握了我們的技術，正在行動！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"심지어, 그게 다가 아닙니다!","JPN":"しかも、それだけじゃないです！","ENG":"And that's not even the worst part!","TWN":"甚至，這還不是全部！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"이 녀석들, 침식체들끼리 협력하고 있어?","JPN":"こいつら、侵食体同士で協力してる？","ENG":"These C.O.s... are they coordinating with each other?!","TWN":"這些傢伙們，侵蝕體之間在合作嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"행동도 수비적이야. 이래서야, 꼭 누군가를 지키려는 것 같잖아…!!","JPN":"行動も守備的だ。これじゃ、まるで誰かを守ろうとしてるみたいじゃないか……！！","ENG":"Their formation's defensive. It's like they're protecting someone...!!","TWN":"行動也很防守。這樣的話，簡直像是想要保護某個人似的…！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_COUNT_NULL_NULL","text":{"KOREA":"돌아가라, 마왕…!","JPN":"帰れ、魔王……！","ENG":"Turn back, Demon Lord...!","TWN":"你回去吧，魔王……！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_COUNT_NULL_NULL","text":{"KOREA":"여긴… 우리의 땅이야……!!","JPN":"ここは……我々の地だ……！！","ENG":"This... is our land...!!","TWN":"這裡是……我們的土地……！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"겉모습만 같은 괴물을 상대했던 클리포트 게임 때와는 다르다.","JPN":"外見だけが同じの化け物を相手したクリフォトゲームの時とは違う。","ENG":"This is nothing like the Qliphoth Game, where we faced mindless monsters.","TWN":"這與逆卡巴拉遊戲中對抗外表相似的怪物時不同。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"지금은 나 자신. 혹은, 가문의 기사와 싸우는 기분이야.","JPN":"今は自分自身、あるいは、家門の騎士と戦っている気分だ。","ENG":"Now, it feels like I'm fighting myself, or the knights from my own house.","TWN":"現在是我自己。或者說，感覺像是在和家族的騎士戰鬥。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이래서는 단원들의 사기가…!!","JPN":"これでは団員の士気が……！！","ENG":"This will break the others' morale fast...!","TWN":"這樣下去，隊員們的士氣會……！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"마왕의 영향력에서 벗어났기에 그 수준은 비루해졌으나…….","JPN":"魔王の影響力から離れて、そのレベルは落ちてしまったが……","ENG":"They've weakened since breaking free from the Demon Lord's influence...","TWN":"雖然擺脫了魔王的影響力，但其程度已經變得微不足道……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"역설적으로, 그럴수록 인간에 가까워지는 것이 그림자지.","JPN":"逆説的に、そうなるほど人間に近くなるのがシャドウだ。","ENG":"But paradoxically, that makes Shadows more human.","TWN":"諷刺的是，越是這樣，暗影就越接近人類。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"지키는 입장이 아닌 약탈하는 자의 입장이 되어 네놈들은 선택할 수밖에 없다.","JPN":"守る立場ではなく略奪する者の立場となり、貴様らは選ぶしかないだろう。","ENG":"Now that you're in the role of the aggressor, you have no choice but to choose.","TWN":"你們只能選擇成為掠奪者，而不是守護者。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"기사의 긍지를 포기할 것인지. 혹은, 소중한 동료를 포기할 것인지 말이야.","JPN":"騎士の誇りを諦めるか、それとも大切な仲間を諦めるかをな。","ENG":"Will you abandon your pride as a knight, or sacrifice your comrades?","TWN":"是要放棄騎士的自尊，還是要放棄珍貴的同伴呢？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"물론, 각오를 다질 시간 따위 줄 생각 없지만.","JPN":"無論、覚悟を決める時間など与えてやるつもりはない。","ENG":"Of course, I won't be giving you time to think about it.","TWN":"當然，我也不會給你們準備的時間。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"모처럼의 무대가 무료하군, 아셀라 경.","JPN":"せっかくの舞台が退屈だ、アセッラ卿。","ENG":"This show is starting to drag, Dame Ascella.","TWN":"難得的舞臺真是無聊啊，亞瑟拉。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"이쯤에서 조금 흥을 돋우는 게 어떤가?","JPN":"ここらで少し盛り上げるのはどうだ？","ENG":"Care to liven things up a bit?","TWN":"差不多來刺激的怎麼樣？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아하하~! 우리 단장님 성격 진~짜 나쁘다!","JPN":"あはは～！　うちの団長、本当に性格悪すぎ！","ENG":"Ahaha! You've got one twisted personality, Captain!","TWN":"啊哈哈～！我們團長的性格真～是差勁！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그래서 재밌어! 완전 최고야!!","JPN":"だから面白いんだよね！　もう最高！！","ENG":"That's what makes him so much fun! I love it!!","TWN":"所以很有趣！真是太棒了！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"안돼…….","JPN":"ダメ……","ENG":"No...","TWN":"不……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"도망치세요, 여러분!!","JPN":"皆さん、逃げて！！","ENG":"Everyone, run!!","TWN":"快逃啊，各位！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"뭐, 뭐야. 이거 놓지 못해?","JPN":"な、なんだ。離せ！","ENG":"W-what the–?! Let me go!","TWN":"什、什麼啊。放開我！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":null}}}]`);export{e as default};